window.allTests["test_u1_genel_3"] = [
    {
        soru: "<i>'Malazgirt bir nedenin değil, uzun bir sürecin sonucudur'</i><br><br><b>Türklerin Anadolu'ya yönelik ilk büyük akınlarını değerlendiren bir tarihçinin bu saptamasını destekleyen en güçlü kanıt aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Malazgirt Savaşı'nda Selçuklu ordusunun sayısal üstünlüğü",
            "B) 1040'lardan itibaren Türkmen akıncılarının Doğu Anadolu'ya sürekli ve sistematik akınlar düzenlemesi",
            "C) Bizans'ın Malazgirt öncesinde sınır savunmasını tamamen terk etmesi",
            "D) Abbasi halifesinin Türklere Anadolu'ya geçmeleri için resmi izin vermesi",
            "E) Selçuklu ordusunun Bizans'a ait tüm kalelerini Malazgirt öncesinde ele geçirmesi"
        ],
        cevap: "B) 1040'lardan itibaren Türkmen akıncılarının Doğu Anadolu'ya sürekli ve sistematik akınlar düzenlemesi",
        aciklama: "Türk akınları, Selçuklu Devleti'nin henüz kuruluş aşamasında bile Doğu Anadolu'ya yönelmeye başlamıştı. Pasinler (1048), Arzen (1048-49) ve başka pek çok bölgede gerçekleştirilen akınlar, Malazgirt'ten onlarca yıl önce Türkmenlerin bu coğrafyayı tanıdığını ve büyük bir zafer için zeminin hazır olduğunu göstermektedir. Malazgirt yalnızca bu uzun süreci resmî bir zirveye taşıyan savaştır."
    },
    {
        soru: "<b>Aşağıdaki ifadelerden hangisi Malazgirt Savaşı'nın (1071) Bizans İmparatorluğu açısından uzun vadeli sonuçlarını en doğru biçimde özetler?</b>",
        secenekler: [
            "A) Bizans, Malazgirt yenilgisinin ardından kısa sürede toparlanarak Anadolu kontrolünü yeniden kazanmıştır.",
            "B) Malazgirt, Bizans'ın Anadolu'daki demografik ve ekonomik kayıplarını kalıcılaştırmış; imparatorluğun ağırlık merkezini Balkanlara kaydırmıştır.",
            "C) Malazgirt yalnızca sınır boylarında küçük toprak kayıplarına yol açmış, iç Anadolu etkilenmemiştir.",
            "D) Bizans bu yenilginin ardından derhal Haçlılarla ittifak kurarak topraklarını geri almıştır.",
            "E) Malazgirt'ten sonra Bizans, İslam dünyasıyla barış antlaşması imzalayarak statükoyu korumayı tercih etmiştir."
        ],
        cevap: "B) Malazgirt, Bizans'ın Anadolu'daki demografik ve ekonomik kayıplarını kalıcılaştırmış; imparatorluğun ağırlık merkezini Balkanlara kaydırmıştır.",
        aciklama: "Malazgirt Savaşı, kısa vadede bir savaş kaybından çok daha derin yapısal sonuçlar doğurmuştur. Savaş sonrasında Bizans ordusu ağır kayıplar vermiş; vergi gelirleri azalmış; Türkmen göç dalgaları Anadolu'nun demografik yapısını dönüştürmeye başlamıştır. Bizans'ın ağırlık merkezinin zamanla Balkanlara kayması, imparatorluğun Anadolu üzerindeki denetimini giderek yitirmesinin kaçınılmaz bir yansımasıdır."
    },
    {
        soru: "<b>Haçlı Seferleri'nin Türk-İslam dünyasına etkileri analiz edildiğinde, aşağıdaki yorumlardan hangisi tarihsel gerçekliğe en uygun düşer?</b>",
        secenekler: [
            "A) Haçlı Seferleri Türk devletlerinin kalıcı çöküşüne neden olmuştur.",
            "B) Haçlı Seferleri hem tehdit hem de fırsat unsuru olmuş; kısa vadede toprak kayıpları yaşanmış, uzun vadede ise bu seferler Türk-İslam dünyasını siyasi açıdan mobilize etmiştir.",
            "C) Haçlı Seferleri Türklerle Hristiyanlar arasında hiçbir siyasi ilişki doğurmamıştır.",
            "D) Haçlı Seferleri Selçukluların Moğollara karşı ittifak kurmasına zemin hazırlamıştır.",
            "E) Haçlı Seferleri Anadolu'daki Türk nüfusunu kalıcı olarak azaltmıştır."
        ],
        cevap: "B) Haçlı Seferleri hem tehdit hem de fırsat unsuru olmuş; kısa vadede toprak kayıpları yaşanmış, uzun vadede ise bu seferler Türk-İslam dünyasını siyasi açıdan mobilize etmiştir.",
        aciklama: "Haçlı Seferleri, Türk-İslam dünyası üzerinde paradoksal bir etki bırakmıştır. I. Haçlı Seferi'nde Anadolu Selçuklularının İznik gibi önemli kentleri kaybetmesi kısa vadeli bir gerilemeyi temsil eder. Bununla birlikte Haçlıların bölgede kalıcı bir hâkimiyet kuramaması ve II. Kılıç Arslan'ın Miryokefalon'daki (1176) zaferi, uzun vadeli dengelerin Türkler lehine döndüğünü göstermektedir. Bunun yanı sıra Haçlı tehdidi, Sünni İslam dünyasının savunma reflekslerini harekete geçirerek ulemanın devlet ile ilişkisini yeniden biçimlendirmiştir."
    },
    {
        soru: "<b>Kösedağ Savaşı'nda (1243) Moğollar karşısında yenilen Anadolu Selçuklu Devleti'nin siyasi durumunu en doğru betimleyen seçenek hangisidir?</b>",
        secenekler: [
            "A) Selçuklu Devleti Kösedağ'ın ardından fiilen yıkılmış ve toprakları doğrudan Moğol yönetimine girmiştir.",
            "B) Selçuklu sultanları Moğol hâkimiyetini kabul etmiş; devlet ilhan'lara bağlı bir vasal konumuna düşerek bir süre daha varlığını sürdürmüştür.",
            "C) Moğollar Selçuklu topraklarını fethettikten sonra İslamiyet'i kabul ederek Selçuklu kültürünü benimsemiştir.",
            "D) Kösedağ yenilgisinin ardından Selçuklu sultanları Bizans İmparatorluğu'na sığınmıştır.",
            "E) Selçuklu Devleti Kösedağ'dan hemen sonra parçalanmış ve yerini Osmanlı Devleti almıştır."
        ],
        cevap: "B) Selçuklu sultanları Moğol hâkimiyetini kabul etmiş; devlet ilhan'lara bağlı bir vasal konumuna düşerek bir süre daha varlığını sürdürmüştür.",
        aciklama: "Kösedağ Savaşı (1243) Selçuklu Devleti'ni derhal yıkmamış; ancak fiilî egemenliğini büyük ölçüde ortadan kaldırmıştır. Sultanlar, İlhanlı Devleti'nin vassalı konumuna düşmüş; siyasi kararlar giderek Moğol noyanlarının denetimine girmiştir. Bu vasal ilişki, Selçuklu kurumsal varlığının biçimsel sürmesine olanak tanımış; ancak merkezi otoritenin çözülmesiyle birlikte Anadolu'da beyliklerin ortaya çıkışı hız kazanmıştır."
    },
    {
        soru: "<b>Aşağıdaki tarihsel olaylar kronolojik sıraya konulduğunda hangi seçenek doğru sıralamayı verir? I. Miryokefalon Savaşı II. Dandanakan Savaşı III. Kösedağ Savaşı IV. Malazgirt Savaşı V. I. Haçlı Seferi</b>",
        secenekler: [
            "A) I – II – III – IV – V",
            "B) II – IV – V – I – III",
            "C) IV – II – V – I – III",
            "D) II – V – IV – I – III",
            "E) V – II – IV – I – III"
        ],
        cevap: "B) II – IV – V – I – III",
        aciklama: "Doğru sıralama: Dandanakan (1040) → Malazgirt (1071) → I. Haçlı Seferi (1096-99) → Miryokefalon (1176) → Kösedağ (1243) biçimindedir. Bu kronoloji Türk tarihinin Orta Asya'dan Anadolu'ya uzanan sürecini özetler: Selçuklu devletinin kuruluşu, Anadolu'nun kapılarının açılması, Haçlı baskısı, Türk kalıcılığının tescili ve Moğol müdahalesi. Bu sıralamayı kavramak, olaylar arası neden-sonuç ilişkisini çözümlemenin temel önkoşuludur."
    },
    {
        soru: "<i>'Anadolu'nun Türk yurdu haline gelmesi salt askeri fetihle açıklanamaz; demografik dönüşüm en az askeri zaferler kadar belirleyici olmuştur.'</i><br><br><b>Bir tarih öğrencisinin öne sürdüğü bu argümanı en güçlü biçimde destekleyen örnek aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Selçuklu ordusunun büyük kentleri fetheden güçlü bir savunma hattı oluşturması",
            "B) Malazgirt sonrasında Türkmen boylarının Anadolu'ya dalga dalga göç ederek yerleşmesi ve bölgenin dilsel, kültürel yapısını köklü biçimde dönüştürmesi",
            "C) Selçuklu sultanlarının yerel Hristiyan nüfusu zorla İslamlaştırması",
            "D) Türklerin Anadolu'ya geçişinin yalnızca belirli bir kanaldan sistematik biçimde gerçekleşmesi",
            "E) Bizans'ın Moğollarla ittifak kurarak Türk göçünü engellemeye çalışması"
        ],
        cevap: "B) Malazgirt sonrasında Türkmen boylarının Anadolu'ya dalga dalga göç ederek yerleşmesi ve bölgenin dilsel, kültürel yapısını köklü biçimde dönüştürmesi",
        aciklama: "Anadolu'nun Türk yurdu haline gelmesi, yalnızca askeri zaferlerle değil; en az bunlar kadar önemli olan demografik dönüşümle açıklanabilir. Malazgirt'in ardından on binlerce Türkmen ailesi Anadolu'ya yerleşmiş; yaylak-kışlak düzeni bu coğrafyaya uyarlanmış; Türkçe zaman içinde bölgenin baskın dili haline gelmiştir. Bu süreç, fetihten bağımsız olarak süregelen ve geri dönüşü imkânsız kılan köklü bir kültürel dönüşümü temsil etmektedir."
    },
    {
        soru: "<b>Aşağıdaki önermeleri 'tarihsel açıdan doğru (D)' ya da 'yanlış (Y)' olarak sınıflandırınız ve doğru sınıflandırmayı içeren seçeneği işaretleyiniz. I. Dandanakan Savaşı Selçukluların Bizans'a karşı kazandığı ilk büyük zaferdir. II. Miryokefalon Savaşı Türklerin Anadolu'daki kalıcılığını güvenceye almıştır. III. Moğol İstilası Anadolu'nun Türkleşme sürecini tamamen durduran bir kırılma noktasıdır. IV. I. Haçlı Seferi, Anadolu Selçuklularının başkentlerini geçici olarak kaybetmelerine yol açmıştır.</b>",
        secenekler: [
            "A) I-D, II-D, III-D, IV-D",
            "B) I-Y, II-D, III-Y, IV-D",
            "C) I-D, II-D, III-Y, IV-D",
            "D) I-Y, II-Y, III-D, IV-Y",
            "E) I-D, II-Y, III-D, IV-Y"
        ],
        cevap: "B) I-Y, II-D, III-Y, IV-D",
        aciklama: "I. Dandanakan Savaşı (1040), Selçukluların Gaznelilere karşı kazandığı zaferdir; Bizans'a karşı değil. Bu nedenle I. önerme YANLIŞ'tır. II. Miryokefalon (1176) gerçekten de Türk kalıcılığını güvenceye almıştır; DOĞRU. III. Moğol İstilası Türkleşmeyi durdurmamış; aksine Orta Asya'dan gelen yeni Türkmen dalgalarıyla süreci hızlandırmıştır; YANLIŞ. IV. I. Haçlı Seferi sırasında İznik Selçuklulardan alınmış; başkentlerini geçici olarak kaybetmişlerdir; DOĞRU. Doğru eşleştirme I-Y, II-D, III-Y, IV-D, yani B seçeneğidir."
    },
    {
        soru: "<b>Abbasi Halifesi'nin 1058'de Tuğrul Bey'e 'Doğu'nun ve Batı'nın Sultanı' unvanını vermesi, Türk-İslam tarihinde ne anlam ifade etmektedir?</b>",
        secenekler: [
            "A) Tuğrul Bey'in Abbasi hilafetini fiilen ilga ettiğini göstermektedir.",
            "B) Selçuklu hâkimiyetinin İslam dünyasınca meşrulaştırıldığını ve Türk-İslam sentezinin sembolik düzeyde pekiştirildiğini göstermektedir.",
            "C) Selçukluların Türk siyasi geleneğini tamamen terk ettiğini ortaya koymaktadır.",
            "D) Bu unvan yalnızca sembolik olup Tuğrul Bey'in siyasi gücünü etkilememiştir.",
            "E) Abbasi halifeliğinin siyasi açıdan güçlendiğini ve Selçuklu vesayetinden kurtulduğunu göstermektedir."
        ],
        cevap: "B) Selçuklu hâkimiyetinin İslam dünyasınca meşrulaştırıldığını ve Türk-İslam sentezinin sembolik düzeyde pekiştirildiğini göstermektedir.",
        aciklama: "Abbasi Halifesi Kaim Biemrillah'ın Tuğrul Bey'e verdiği sultan unvanı, Türk-İslam tarihinde simgesel bir kırılma noktasıdır. Bu törenle birlikte Selçuklular yalnızca askeri güç sahibi değil; aynı zamanda İslam dünyasının meşru koruyucusu ve önderi konumuna yükselmiştir. Halife ise fiilî siyasi iktidarını yitirmiş; dinî meşruiyet kaynağı rolüyle sınırlı kalmıştır. Bu ilişki biçimi -sultan siyasi güç, halife dinî meşruiyet- Selçuklu iktidar ideolojisinin temel yapısını oluşturmakta olup Türk-İslam devlet anlayışının özünü yansıtmaktadır."
    },
    {
        soru: "<b>Anadolu Selçuklu Devleti'nde Türk geleneksel yönetim anlayışı ile İran-İslam bürokratik geleneğinin bir araya getirildiği yönetim biçimi için en doğru tanım hangisidir?</b>",
        secenekler: [
            "A) Teokratik yönetim: Tüm kararların din âlimlerine bırakıldığı sistem",
            "B) Türk-İslam sentezi: Türk töresinin devlet yönetiminde İslami kurumlar ve İran bürokratik geleneğiyle harmanlandığı karma model",
            "C) Feodal yönetim: Bağımsız yerel beylerin merkezi otoriteden bağımsız olduğu sistem",
            "D) Tek adam yönetimi: Sultanın tüm yetkiyi münferiden kullandığı katı merkeziyetçi sistem",
            "E) Şura yönetimi: Tüm kararların ulema meclisi tarafından alındığı danışmalı sistem"
        ],
        cevap: "B) Türk-İslam sentezi: Türk töresinin devlet yönetiminde İslami kurumlar ve İran bürokratik geleneğiyle harmanlandığı karma model",
        aciklama: "Türk-İslam devlet modeli, farklı geleneklerin bilinçli sentezinden doğmuştur. Türk töresi; hükümdarın adaleti, halkın refahı ve askeri güç gibi değerleri ön plana çıkarırken, İran bürokratik geleneği divanlı yönetim yapısını ve yazılı hukuk kültürünü getirmiştir. İslam ise meşruiyet zeminini ve ahlaki çerçeveyi sağlamıştır. Bu sentez, Nizam-ül Mülk'ün Siyasetname adlı eserinde kuramsal boyutuyla ortaya konmuştur."
    },
    {
        soru: "<b>Selçuklu döneminde 'melik' unvanlı şehzadelerin taşra yönetimine atanması uygulaması değerlendirildiğinde, bu sistemin hangi temel çelişkiyi barındırdığı görülmektedir?</b>",
        secenekler: [
            "A) Şehzadeler yönetim deneyimi kazanırken merkezi otoritenin güçsüzleşmesine zemin hazırlamıştır.",
            "B) Bu sistem yalnızca Türk hanedanlıklarına özgüdür; İslam öncesi dönemde örneği yoktur.",
            "C) Şehzadelerin taşraya gönderilmesi, merkezde yaşanabilecek saray komplosunu önlemek için tasarlanmış bir güvenlik tedbiridir.",
            "D) Melik sistemi, İran valilerinin görevine son vererek tam merkezileşmeyi sağlamıştır.",
            "E) Bu uygulamanın olumlu ya da olumsuz hiçbir sonucu gözlemlenmemiştir."
        ],
        cevap: "A) Şehzadeler yönetim deneyimi kazanırken merkezi otoritenin güçsüzleşmesine zemin hazırlamıştır.",
        aciklama: "Şehzadelerin melik unvanıyla taşra yönetimine atanması, onların idari deneyim edinmesini ve eyalet yönetiminin denetlenmesini sağlamıştır. Ancak aynı zamanda merkezi otorite zayıfladığında bu şehzadelerin bağımsız hareket etmesine zemin hazırlamıştır. Selçuklu tarihi; Sultan Melikşah sonrasında yaşanan hanedan içi mücadelelerin büyük bölümünün bu melik sistemiyle doğrudan bağlantılı olduğunu göstermektedir."
    },
    {
        soru: "<b>Selçuklu ordusunda 'Türkopol' ya da Türk asıllı paralı asker kullanımı dışında, farklı etnik kökenlerden savaşçıların orduya dahil edilmesi ne tür sonuçlar doğurmuştur? Aşağıdaki yorumlardan hangisi tarihsel gerçekliği en doğru yansıtır?</b>",
        secenekler: [
            "A) Farklı etnik kökenlerden savaşçıların orduya alınması yalnızca askeri güçsüzlüğün göstergesidir.",
            "B) Bu uygulama orduyu güçlendirirken farklı grupların sadakat çatışmalarına da zemin hazırlamış; uyum sağlayan unsurlar zaman içinde sisteme entegre olurken uyum sağlamayanlar istikrarsızlık kaynağı olmuştur.",
            "C) Selçuklu ordusu tarihte ilk kez farklı etnik unsurları birleştiren çok uluslu bir model kurmuştur.",
            "D) Farklı etnik unsurların dahil edilmesi sultanın siyasi otoritesini doğrudan pekiştirmiştir.",
            "E) Bu uygulama yalnızca İlhanlı döneminde görülmüş; Büyük Selçuklu döneminde uygulanmamıştır."
        ],
        cevap: "B) Bu uygulama orduyu güçlendirirken farklı grupların sadakat çatışmalarına da zemin hazırlamış; uyum sağlayan unsurlar zaman içinde sisteme entegre olurken uyum sağlamayanlar istikrarsızlık kaynağı olmuştur.",
        aciklama: "Selçuklu ordusunda Türkmen, gulam, Kürt, İranlı ve zaman zaman Hristiyan savaşçılar bir arada görev yapmıştır. Bu çeşitlilik; ordunun geniş coğrafyalarda etkin olmasını kolaylaştırmış; farklı savaş tekniklerini ve yerel bilgiyi bünyesine katmıştır. Öte yandan sadakat çatışmaları, özellikle kriz dönemlerinde belirginleşmiştir: Malazgirt'te Uz ve Peçenek unsurların Türk saflarına geçmesi bunun en çarpıcı örneğidir."
    },
    {
        soru: "<b>Türk-İslam devletlerinde hükümdarın meşruiyetini pekiştiren araçlar incelendiğinde, 'kılıç hakkı', 'halife onayı' ve 'Türk töresine dayalı karizmatik otorite' üç ayrı meşruiyet kaynağı olarak öne çıkmaktadır. Bu üç kaynağın bir arada işlev görmesi hangi sonucu doğurmuştur?</b>",
        secenekler: [
            "A) Bu üç meşruiyet kaynağının çakışması hükümdarlık otoritesini tek boyutlu olmaktan çıkararak daha katmanlı ve karmaşık bir yapıya büründürmüştür.",
            "B) Üç farklı meşruiyet kaynağının var olması, hükümdar otoritesini zayıflatarak yönetim boşlukları yaratmıştır.",
            "C) Bu kaynaklar yalnızca büyük Selçuklu sultanları için geçerliydi; Anadolu beyliklerinde geçerliliğini yitirmiştir.",
            "D) Halife onayı diğer iki kaynağı devre dışı bırakmış; sultan yalnızca dini meşruiyete dayanmıştır.",
            "E) Bu üç kaynak birbirini dışladığından sultanlar bunlardan yalnızca birini kullanmıştır."
        ],
        cevap: "A) Bu üç meşruiyet kaynağının çakışması hükümdarlık otoritesini tek boyutlu olmaktan çıkararak daha katmanlı ve karmaşık bir yapıya büründürmüştür.",
        aciklama: "Türk-İslam hükümdarları, meşruiyetlerini yalnızca askeri güce ya da yalnızca dinî onaya dayandırmamış; bu kaynakları ustalıkla bir araya getirmiştir. Kılıç hakkı (fetihlere dayanan güç ve başarı), Türk töresine bağlı hanlık karizması ve halifenin sembolik onayı bir arada işlev görmüştür. Bu katmanlı meşruiyet yapısı, sultanın farklı toplum kesimlerine (Türkmen savaşçılar, ulema, İranlı bürokratlar) hitap etmesini mümkün kılmış; ancak her kaynağın kendi gerekliliklerini beraberinde getirmesi yönetimi karmaşık bir denge sanatına dönüştürmüştür."
    },
    {
        soru: "<b>Selçuklu devlet anlayışında 'adalet dairesi' kavramı ne anlama gelmektedir ve hangi toplumsal ilişkiyi tanımlamaktadır?</b>",
        secenekler: [
            "A) Yalnızca hukuki yargı usulünü düzenleyen bir kavramdır.",
            "B) Sultanın adaleti → halkın refahı → vergi gelirleri → güçlü ordu → güvenlik ve adalet döngüsünü ifade eden, siyasi düzenin sürdürülebilirliğini açıklayan bütüncül bir devlet felsefesi modelidir.",
            "C) İslam hukukunda cezai yaptırımları belirleyen bir ilkedir.",
            "D) Halk ile ulema arasındaki ilişkiyi düzenleyen dinî bir kavramdır.",
            "E) Yalnızca Bizans kökenli bir yönetim anlayışının Selçuklulara aktarılmış biçimidir."
        ],
        cevap: "B) Sultanın adaleti → halkın refahı → vergi gelirleri → güçlü ordu → güvenlik ve adalet döngüsünü ifade eden, siyasi düzenin sürdürülebilirliğini açıklayan bütüncül bir devlet felsefesi modelidir.",
        aciklama: "Adalet dairesi (daire-i adliye), Selçuklu ve daha geniş anlamda Türk-İslam siyasi düşüncesinin temel kavramlarından biridir. Bu modele göre: hükümdar adaleti tesis eder → halk refah içinde yaşar → hazine vergilerle dolar → sultan güçlü bir ordu besler → ordu düzen ve güvenliği sağlar → güvenli ortamda üretim ve ticaret artar → hazine geliri yeniden yükselir. Bu döngüsel ilişki, Nizam-ül Mülk'ün Siyasetname'sinde sistematik biçimde ortaya konmuş olup Türk-İslam devlet düşüncesinin belkemiğini oluşturmaktadır."
    },
    {
        soru: "<b>Anadolu Selçuklu Devleti'nde sultan ile ulema (din âlimleri) arasındaki ilişki nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Sultan, ulemayı tamamen devlet otoritesine bağlı kılarak onların bağımsız dinî yorumlarını engellemiştir.",
            "B) Ulema ve sultan birbirinin meşruiyetini pekiştiren karşılıklı bağımlılık ilişkisi içindeydi: sultanlar medreseler kurarak ulemayı desteklerken, ulema sultanlara dinî meşruiyet sağlıyordu.",
            "C) Ulema siyasi alandan tamamen çekilerek yalnızca ibadet hayatıyla ilgilenmiştir.",
            "D) Selçuklu sultanları ulemayla hiçbir kurumsal ilişki kurmamıştır.",
            "E) Ulema, sultan otoritesine karşı düzenli olarak muhalefet etmiş ve halk isyanlarını yönetmiştir."
        ],
        cevap: "B) Ulema ve sultan birbirinin meşruiyetini pekiştiren karşılıklı bağımlılık ilişkisi içindeydi: sultanlar medreseler kurarak ulemayı desteklerken, ulema sultanlara dinî meşruiyet sağlıyordu.",
        aciklama: "Selçuklu döneminde sultan-ulema ilişkisi karşılıklı çıkara dayanan organik bir bağ üzerine kurulmuştur. Sultanlar medrese inşa etmek, vakıf kurmak ve ulemaya maaş bağlamak suretiyle bu sınıfı himaye etmiş; ulema ise camilerde okunacak hutbelerde sultanı öven dualar okuyarak ve fetvalar yayımlayarak dinî meşruiyet üretmiştir. Bu ilişki bazı dönemlerde gerginleşmiş olsa da genel olarak işbirlikçi bir karakterde sürmüştür."
    },
    {
        soru: "<i>Görüş I: 'Selçuklu devleti, merkezi otoriteyi mümkün olduğunca güçlü tutan ve bölgesel özerkliği sınırlayan yoğun merkeziyetçi bir yapıya sahipti.' Görüş II: 'Selçuklu devleti, geniş coğrafyanın zorunluluğuyla taşraya önemli yetkiler devretmek durumunda kalmış; bu durum zaman zaman merkezi otoritenin aşınmasına yol açmıştır.'</i><br><br><b>Aşağıda Selçuklu devlet yönetimine ilişkin iki farklı tarihçi görüşü verilmiştir: Bu iki görüşü uzlaştıran en tutarlı yorum hangisidir?</b>",
        secenekler: [
            "A) İki görüş tamamen çelişmektedir; birini kabul etmek diğerini reddetmeyi zorunlu kılar.",
            "B) Her iki görüş de doğrudur; Selçuklu yönetimi farklı dönemlerde ve bölgelerde merkeziyetçilik ile adem-i merkeziyetçilik arasında bir denge kurmaya çalışmıştır.",
            "C) I. görüş Büyük Selçuklular için; II. görüş yalnızca Anadolu Selçukluları için geçerlidir.",
            "D) Her iki görüş de desteklenebilir kanıttan yoksundur; Selçuklu devlet yapısı hakkında kesin bir şey söylenemez.",
            "E) I. görüş doğru, II. görüş yanıltıcıdır; çünkü Selçuklular güçlü merkeziyetçiliği her dönemde korumuştur."
        ],
        cevap: "B) Her iki görüş de doğrudur; Selçuklu yönetimi farklı dönemlerde ve bölgelerde merkeziyetçilik ile adem-i merkeziyetçilik arasında bir denge kurmaya çalışmıştır.",
        aciklama: "Selçuklu yönetim yapısı, tek bir modelle açıklanamayacak kadar dinamik bir nitelik taşımaktadır. Sultanın güçlü olduğu dönemlerde (örneğin Melikşah dönemi) merkezi denetim belirgin biçimde ön plana çıkarken; veraset krizleri, Moğol baskısı ya da sınır bölgelerinin uzaklığı gibi etkenler adem-i merkeziyetçi eğilimleri güçlendirmiştir. İkta sistemi, melik uygulaması ve uç beylikleri bu ikiliği somutlaştıran kurumsal örneklerdir. İki görüşü karşıt değil, tamamlayıcı olarak okumak; Selçuklu yönetim tarihini dönemsel dalgalanmalar içinde kavramayı sağlar."
    }
];

window.allTests["test_u1_genel_4"] = [
    {
        soru: "<b>Selçuklu devlet teşkilatında 'Divan-ı Mezalim'in işlevi aşağıdakilerden hangisiyle doğru biçimde tanımlanmıştır?</b>",
        secenekler: [
            "A) Devletin mali hesaplarını tutmak ve bütçeyi denetlemek",
            "B) Ordunun asker sayısını kayıt altına almak ve maaşları düzenlemek",
            "C) Halkın devlet görevlilerinden kaynaklanan haksızlıklarını doğrudan sultana ya da kadıya ilettiği ve çözüme kavuşturulduğu yüksek şikâyet ve adalet mahkemesi",
            "D) Yabancı devletlerle yazışmaları ve antlaşmaları düzenlemek",
            "E) Dini vakıfların yönetimini ve denetimini üstlenmek"
        ],
        cevap: "C) Halkın devlet görevlilerinden kaynaklanan haksızlıklarını doğrudan sultana ya da kadıya ilettiği ve çözüme kavuşturulduğu yüksek şikâyet ve adalet mahkemesi",
        aciklama: "Divan-ı Mezalim (Şikâyetler Divanı), Selçuklu adalet anlayışının kurumsal yansımasıdır. Bu divanda sultan ya da onun yetkili kıldığı bir kadı, halkın devlet memurlarından, ordu mensuplarından ya da ikta sahiplerinden kaynaklanan şikâyetlerini bizzat dinler ve karara bağlardı. Bu uygulama; hükümdarın adaleti doğrudan tesis etme sorumluluğunu simgelemekte ve 'adalet dairesi' kavramının kurumsal yaşama geçirilmesini temsil etmektedir."
    },
    {
        soru: "<b>Selçuklu döneminde şehirlerin ekonomik kalbini oluşturan ve farklı mesleklerden esnafın bir arada faaliyet gösterdiği kapalı çarşı yapısına verilen isim nedir?</b>",
        secenekler: [
            "A) Ribat",
            "B) Bedesten (kapalı çarşı / arasta)",
            "C) Zaviye",
            "D) İmaret",
            "E) Divan-ı İnşa"
        ],
        cevap: "B) Bedesten (kapalı çarşı / arasta)",
        aciklama: "Bedesten ya da kapalı çarşı (arasta), Selçuklu ve Osmanlı şehirciliğinin temel ticari mekânıdır. Bu yapılar; farklı meslek gruplarına ayrılmış çarşılar, kuyumcular, kumaşçılar ve diğer zanaatkârları bir arada barındırırdı. Vakıf sistemiyle desteklenen bu ticaret mekânları, hem ekonomik bir işlev hem de toplumsal bir buluşma noktası niteliği taşırdı."
    },
    {
        soru: "<b>Anadolu Selçuklu döneminde vakıf sisteminin ekonomik ve sosyal işlevleri birlikte değerlendirildiğinde, bu kurumun en belirgin özelliği hangisidir?</b>",
        secenekler: [
            "A) Vakıflar yalnızca cami ve medrese inşaatını finanse olmuştur.",
            "B) Vakıflar; eğitim, sağlık, ulaşım ve sosyal yardım gibi alanlarda devlet müdahalesi olmaksızın toplumsal ihtiyaçları karşılayan özgün bir sivil finansman modeli oluşturmuştur.",
            "C) Vakıflar sultanın doğrudan denetiminde olduğundan özerk bir işlev üstlenememiştir.",
            "D) Vakıf sistemi yalnızca Büyük Selçuklu döneminde uygulanmış; Anadolu Selçuklularında görülmemiştir.",
            "E) Vakıflar gelirlerini tüccarların bağışlarından değil, yalnızca tarımsal arazilerden elde etmiştir."
        ],
        cevap: "B) Vakıflar; eğitim, sağlık, ulaşım ve sosyal yardım gibi alanlarda devlet müdahalesi olmaksızın toplumsal ihtiyaçları karşılayan özgün bir sivil finansman modeli oluşturmuştur.",
        aciklama: "Vakıf sistemi, Selçuklu toplumunun en özgün kurumsal buluşlarından biridir. Mülkünü vakfeden kişi; gelirlerini belirli bir kamusal amaca -okul, hastane, kervansaray, su tesisi, yoksul sofrası- sürekli olarak tahsis ederdi. Bu mekanizma sayesinde okul, hastane (dâru'ş-şifa), kervansaray, çeşme ve imarethane gibi pek çok kamu hizmeti devlet bütçesine bağlı kalmaksızın toplumun kendi öz kaynakları aracılığıyla karşılanmıştır. Vakıf kurumunun bu özerk finansman modeli, Selçuklu kentlerinin sosyal altyapısının sürdürülebilirliğini güvence altına almıştır."
    },
    {
        soru: "<b>Anadolu Selçuklu döneminde farklı din mensuplarının (Rum Ortodoks, Ermeni, Süryani Hristiyanlar, Yahudiler ve Müslümanlar) bir arada yaşaması değerlendirildiğinde, bu çok dinli yapının ekonomik boyutu için hangisi söylenebilir?</b>",
        secenekler: [
            "A) Farklı dinlerden topluluklar ayrı ekonomik alanlarda faaliyet göstermiş; ticari ilişki kurmaları yasaklanmıştır.",
            "B) Bu çok dinli yapı, ticaret ağlarının genişlemesine ve farklı uzmanlıkların bir araya gelerek ekonomik canlılığı artırmasına katkı sağlamıştır.",
            "C) Müslüman tüccarlar her zaman ekonomik ayrıcalıklara sahip olduğundan diğer topluluklarla rekabet edememiştir.",
            "D) Farklı din mensupları yalnızca tarım alanında birlikte çalışmış; ticari hayat tek bir cemaatin tekeline girmiştir.",
            "E) Bu çoğulcu yapı, Selçuklu döneminde hiçbir ekonomik soruna yol açmamış ve tamamen uyum içinde sürmüştür."
        ],
        cevap: "B) Bu çok dinli yapı, ticaret ağlarının genişlemesine ve farklı uzmanlıkların bir araya gelerek ekonomik canlılığı artırmasına katkı sağlamıştır.",
        aciklama: "Anadolu Selçuklu şehirlerindeki çok dinli yapı, ekonomik hayatı zenginleştiren bir çeşitlilik kaynağı olarak işlev görmüştür. Rum ve Ermeni zanaatkârlar, Yahudi tüccarlar ve Müslüman esnaf; farklı üretim teknikleri, ticaret ağları ve finansman yöntemleri ile ekonomik ekosisteme katkı sunmuştur. Bu çeşitlilik, özellikle uluslararası ticaret güzergahlarının kesiştiği Anadolu için büyük bir avantaj oluşturmuştur."
    },
    {
        soru: "<b>Selçuklu döneminde Anadolu'da 'dâru'ş-şifa' olarak bilinen kurumların varlığı, dönemin sosyal yapısı hakkında ne tür bir çıkarımı destekler?</b>",
        secenekler: [
            "A) Bu kurumlar yalnızca saray mensuplarına hizmet vermiştir.",
            "B) Dâru'ş-şifaların varlığı, devletin ve toplumun sağlığı bir kamu hizmeti olarak ele aldığını; bu hizmetin vakıf sistemiyle geniş halk kesimlerine ulaştırıldığını göstermektedir.",
            "C) Bu kurumlar yalnızca dini eğitim veren yapılar olup sağlık hizmetiyle ilgisi yoktur.",
            "D) Dâru'ş-şifalar, Anadolu'da yalnızca Moğol döneminde ortaya çıkmıştır.",
            "E) Bu yapılar yalnızca şehir merkezlerinde değil, her köyde kurulmuştur."
        ],
        cevap: "B) Dâru'ş-şifaların varlığı, devletin ve toplumun sağlığı bir kamu hizmeti olarak ele aldığını; bu hizmetin vakıf sistemiyle geniş halk kesimlerine ulaştırıldığını göstermektedir.",
        aciklama: "Dâru'ş-şifalar (şifahaneler), Selçuklu kentlerinin sosyal altyapısının en önemli halkalarından biridir. Divriği'deki Turan Melek Dâru'ş-Şifası (1228), Kayseri'deki Gevher Nesibe Dâru'ş-Şifası ve Sivas'taki Dâru'ş-Şifa bunların en bilinen örnekleridir. Bu kurumlar vakıf gelirleriyle finanse edilmiş; hastalara ücretsiz ya da düşük ücretli hizmet sunmuştur. Aynı zamanda tıp eğitimi de bu yapılarda gerçekleştirilmiştir. Bu durum, Selçuklu devlet anlayışında sağlık hizmetinin bir kamu sorumluluğu olarak benimsendiğini açıkça ortaya koymaktadır."
    },
    {
        soru: "<b>Anadolu Selçuklu döneminde 'ribat' kurumunun işlevi değerlendirildiğinde, bu yapıların sınır boylarındaki sosyal ve askeri önemi için hangisi en doğru tanımı sunar?</b>",
        secenekler: [
            "A) Ribatlar yalnızca uzak bölgelerdeki ticaret hanları olarak inşa edilmiştir.",
            "B) Ribatlar; hem sınır boylarında askeri savunma üssü hem de tasavvuf erleri (gaziler, dervişler) için manevi eğitim mekânı işlevi üstlenmiştir.",
            "C) Ribatlar, devlet tarafından değil yalnızca özel şahıslar tarafından finanse edilen lüks konaklama yapılarıydı.",
            "D) Ribatlar şehir merkezlerinde inşa edilmiş olup kırsal alanlarda görülmemektedir.",
            "E) Ribatlar ile kervansaraylar tamamen aynı işleve sahip olduğundan iki terim birbirinin yerine kullanılabilir."
        ],
        cevap: "B) Ribatlar; hem sınır boylarında askeri savunma üssü hem de tasavvuf erleri (gaziler, dervişler) için manevi eğitim mekânı işlevi üstlenmiştir.",
        aciklama: "Ribat kurumu, İslam dünyasında hem askeri hem de manevi bir çift işlevi bünyesinde barındıran özgün bir yapıdır. Sınır boylarında (uçlarda) konumlanan ribatlar, bir yanda gönüllü savaşçıları (gazileri) barındırır ve sınır güvenliğine katkı sağlarken, öte yanda dervişler ve gezgin sufiler için manevi eğitim mekânı işlevi görürdü. Bu çift işlev, ribatların Anadolu'nun Türkleşme ve İslamlaşma sürecindeki rolünü hem askeri hem de kültürel boyutta güçlendirmiştir."
    },
    {
        soru: "<b>Anadolu Selçuklu döneminde kentsel nüfusun demografik yapısı incelendiğinde, şehirlerin hangi toplumsal katmanlardan oluştuğu görülmektedir? Aşağıdaki seçeneklerden hangisi bu çok katmanlı kentsel yapıyı en doğru biçimde yansıtır?</b>",
        secenekler: [
            "A) Selçuklu şehirleri yalnızca asker ve yöneticilerden oluşmuş; zanaat ve ticaret nüfusuna yer vermemiştir.",
            "B) Şehirler; yönetici-asker sınıfı, ulema, tüccarlar, zanaatkârlar, çiftçiler ve farklı din topluluklarından oluşan çok katmanlı bir demografik yapıya sahipti.",
            "C) Şehirlerde yalnızca Türkmen kökenli nüfus yaşamış; diğer etnik gruplar kırsal alanlara sürülmüştür.",
            "D) Selçuklu döneminde şehirleşme henüz başlangıç aşamasında olduğundan kentsel nüfus ihmal edilebilir düzeydeydi.",
            "E) Şehirlerin demografik yapısı Moğol istilasından önceki ve sonraki dönemlerde hiç değişmemiştir."
        ],
        cevap: "B) Şehirler; yönetici-asker sınıfı, ulema, tüccarlar, zanaatkârlar, çiftçiler ve farklı din topluluklarından oluşan çok katmanlı bir demografik yapıya sahipti.",
        aciklama: "Anadolu Selçuklu şehirleri, ekonomik ve toplumsal açıdan son derece karmaşık bir demografik mozaik barındırıyordu. Yönetici ve asker sınıfı, din eğitimcileri ve hukuk bilginleri (ulema-kadılar), tüccarlar ve kervancılar, zanaatkârlar, çiftçiler ve konar-göçerler ile farklı din topluluklarının mensupları bu kentlerin canlı nüfusunu oluşturuyordu. Bu çeşitlilik; farklı mahalle yapılarında, pazar düzenlemelerinde ve toplumsal örgütlenme biçimlerinde açıkça görünür hale gelmiştir."
    },
    {
        soru: "<b>Bir iktisatçı, Selçuklu döneminin ekonomik başarısını yalnızca coğrafi konuma (İpek Yolu güzergâhı) bağlamaktadır. Eleştirel bir tarihçi bu indirgemeci yoruma karşı hangi argümanları öne sürer?</b>",
        secenekler: [
            "A) Coğrafi konumun hiçbir önemi olmadığını; başarının yalnızca Selçuklu askeri gücüne dayandığını savunur.",
            "B) Coğrafi konumun belirleyici olduğunu kabul eder; ancak Selçuklu döneminin gerileme dönemi olduğunu vurgular.",
            "C) Coğrafi avantajın tek başına yeterli olmadığını; kervansaray altyapısı, güvenlik ortamı, vakıf sistemi ve çok dinli ticaret ağlarının bu potansiyeli dönüştüren bilinçli insani tercihler ve kurumsal düzenlemeler olduğunu savunur.",
            "D) Selçuklu döneminde İpek Yolu'nun Anadolu'yu tamamen devre dışı bıraktığını; bu nedenle ticari başarının başka nedenlerle açıklanması gerektiğini öne sürer.",
            "E) Ticari başarının yalnızca Bizans'tan devreden kurumların ürünü olduğunu savunur."
        ],
        cevap: "C) Coğrafi avantajın tek başına yeterli olmadığını; kervansaray altyapısı, güvenlik ortamı, vakıf sistemi ve çok dinli ticaret ağlarının bu potansiyeli dönüştüren bilinçli insani tercihler ve kurumsal düzenlemeler olduğunu savunur.",
        aciklama: "Coğrafi konum belirleyici bir ön koşul oluştursa da tek başına yeterli değildir. Anadolu'nun ticaret güzergahları üzerindeki konumu İslam öncesinde de mevcuttu; ancak bu potansiyeli tam anlamıyla değerlendiren bilinçli Selçuklu politikaları olmuştur. Kervansaray ağı, yolların güvenliğini sağlayan askeri düzenlemeler, farklı din ve etnik kökenlerden tüccarları kapsayan açık ticaret politikaları ve vakıf sisteminin altyapıyı finanse etmesi; coğrafi avantajı gerçek ekonomik kalkınmaya dönüştüren insani ve kurumsal tercihlerdir."
    },
    {
        soru: "<b>Kaşgarlı Mahmud'un Divânü Lügati't-Türk adlı eserini kaleme almasındaki temel amaç aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Selçuklu devlet yönetimini eleştirmek ve reform önerilerinde bulunmak",
            "B) Türkçenin zenginliğini ve Arapçayla eşdeğer olduğunu kanıtlamak; Türk dilini, coğrafyasını ve kültürünü sistematik biçimde belgelemek",
            "C) İslam öncesi Türk destanlarını derleme ve yayma",
            "D) Selçuklu hükümdarlarına adalet üzerine öğütler vermek",
            "E) Farklı Türk lehçelerini ortak bir yazı diline kavuşturmak"
        ],
        cevap: "B) Türkçenin zenginliğini ve Arapçayla eşdeğer olduğunu kanıtlamak; Türk dilini, coğrafyasını ve kültürünü sistematik biçimde belgelemek",
        aciklama: "Kaşgarlı Mahmud, Divânü Lügati't-Türk'ü (1072-74) kaleme alırken Türkçeyi bir dil olarak kayıt altına almanın ötesinde, Türkçenin Arapça kadar köklü ve soylu bir dil olduğunu bilim dünyasına ispat etme amacı gütmüştür. Eser; sözcük derleme, atasözleri, şiir parçaları ve coğrafya bilgisini içermekte olup aynı zamanda 11. yüzyıl Türk dünyasının en kapsamlı kültürel belgesidir. Eserin adreslendiği okuyucu kitlesinin Arapça bilen bilginler olması, bu kanıtlama amacını açıkça ortaya koymaktadır."
    },
    {
        soru: "<b>Türk-İslam medeniyetinde 'tercüme hareketi'nin bilim tarihindeki önemi değerlendirildiğinde, bu süreç için hangisi en doğru yorumu sunar?</b>",
        secenekler: [
            "A) Tercüme hareketi, Türk-İslam bilginlerinin özgün katkı yapmadığını göstermektedir; yalnızca aktarıcılık işlevi üstlenmişlerdir.",
            "B) Tercüme hareketi; Antik Yunan, Hint ve İran bilgi mirasını Arapçaya kazandırarak bu mirası dönüştürmüş ve üzerine özgün bilimsel katkılar inşa edilebilecek sağlam bir zemin oluşturmuştur.",
            "C) Tercüme hareketi yalnızca Abbasi döneminde kalmış; Selçuklu döneminde sürdürülmemiştir.",
            "D) Tercüme hareketi, Türk-İslam bilginlerinin Yunan bilimiyle doğrudan ilk kez karşılaştığı dönemde başlamıştır.",
            "E) Tercüme hareketi bilimsel gelişimi yavaşlatmış; özgün araştırmanın önünde engel oluşturmuştur."
        ],
        cevap: "B) Tercüme hareketi; Antik Yunan, Hint ve İran bilgi mirasını Arapçaya kazandırarak bu mirası dönüştürmüş ve üzerine özgün bilimsel katkılar inşa edilebilecek sağlam bir zemin oluşturmuştur.",
        aciklama: "Tercüme hareketi (8.-10. yüzyıl), İslam medeniyetinin bilimsel atılımının temel taşını oluşturmaktadır. Aristoteles mantığı, Galen tıbbı, Öklid geometrisi ve Hint matematiksel mirası Arapçaya aktarılmış; ancak bu aktarım yalnızca mekanik bir çeviriden ibaret kalmamıştır. Biruni, İbn Sina ve Farabi gibi Türk-İslam bilginleri bu mirası eleştirel bir gözle yeniden yorumlamış, eksiklerini gidermiş ve üzerine özgün katkılar inşa etmiştir. Bu durum, tercüme hareketinin bir başlangıç noktası olduğunu; Türk-İslam bilginlerinin ise bu zemin üzerinde bağımsız bilim insanları olarak ilerlediğini göstermektedir."
    },
    {
        soru: "<b>Türk-İslam medeniyetinde Farabi'nin (870-950) 'el-Medinetü'l-Fazıla' adlı eseri, dönemin entelektüel iklimini nasıl yansıtmaktadır?</b>",
        secenekler: [
            "A) Farabi bu eserde yalnızca İslam hukukunu sistematize etmiştir.",
            "B) Farabi, Aristoteles'in siyaset felsefesini İslam vahiy anlayışıyla harmanlayarak erdemli şehir-devlet modelini kuramsallaştırmış; bu yaklaşım Türk-İslam siyasi düşüncesinin temelini etkilemiştir.",
            "C) Farabi bu eserde Orta Asya Türk boylarının tarihini kayıt altına almıştır.",
            "D) Eser yalnızca tasavvuf geleneği içinde değer taşıyan bir metin olup siyasi düşünceyle ilgisi yoktur.",
            "E) Farabi bu eserinde Selçuklu devlet yönetimini doğrudan eleştirmiştir."
        ],
        cevap: "B) Farabi, Aristoteles'in siyaset felsefesini İslam vahiy anlayışıyla harmanlayarak erdemli şehir-devlet modelini kuramsallaştırmış; bu yaklaşım Türk-İslam siyasi düşüncesinin temelini etkilemiştir.",
        aciklama: "Farabi'nin 'el-Medinetü'l-Fazıla' (Erdemli Şehir Üzerine), İslam felsefe geleneğinin en özgün yapıtlarından biridir. Farabi, Platon'un ideal devlet fikri ile Aristoteles'in siyaset felsefesini İslam vahiy anlayışıyla bütünleştirerek erdemli toplum ve erdemli lider kavramlarını yeniden tanımlamıştır. Bu felsefi çerçeve; Türk-İslam devlet düşüncesinin, özellikle adalet ve yönetici erdemi anlayışının kuramsal zeminini oluşturmuştur. Nizam-ül Mülk'ün Siyasetname'sinde görülen pratik devlet öğütlerinin ardında Farabi'nin açtığı bu felsefi zemin yatmaktadır."
    },
    {
        soru: "<b>Türk-İslam medeniyetinde Biruni'nin (973-1048) bilim anlayışı incelendiğinde, onun dönemine göre özgün bir yöntem benimsediği görülmektedir. Bu özgünlük aşağıdakilerden hangisiyle en iyi açıklanır?</b>",
        secenekler: [
            "A) Biruni yalnızca matematiksel hesaplama yöntemiyle çalışmış; gözlem ve deney kullanmamıştır.",
            "B) Biruni; farklı kültürlerin bilgi birikimini nesnel biçimde karşılaştıran, gözleme dayanan ve ön yargılardan arındırılmaya çalışan bir yöntem benimseyerek modern bilim anlayışının öncüllerinden biri sayılmaktadır.",
            "C) Biruni çalışmalarını yalnızca İslam hukuku perspektifinden yürütmüştür.",
            "D) Biruni salt çeviri yapan ve özgün katkı sunmayan bir derleyicidir.",
            "E) Biruni'nin yöntemi, Hint ve Yunan bilimini tamamen reddeden bağımsız bir Türk bilim anlayışını temsil eder."
        ],
        cevap: "B) Biruni; farklı kültürlerin bilgi birikimini nesnel biçimde karşılaştıran, gözleme dayanan ve ön yargılardan arındırılmaya çalışan bir yöntem benimseyerek modern bilim anlayışının öncüllerinden biri sayılmaktadır.",
        aciklama: "Biruni (973-1048), bilim tarihinin en özgün düşünürlerinden biridir. Hindistan'ı ve Hint medeniyetini incelerken 'Kitâbü'l-Hind' adlı eserinde kültürel önyargılardan kaçınan, gözleme dayanan ve Hint kaynaklarını kendi özgün bakış açıılarıyla aktaran bir yöntem geliştirmiştir. Matematiksel hesaplama, gözlem ve kaynak eleştirisiyle harmanladığı bu yöntem, onu çağının ötesine geçiren bir bilimsel tutumu yansıtmaktadır. Biruni'nin Batı bilim literatüründe erken modern bilim anlayışının öncüsü olarak değerlendirilmesi, bu metodolojik özgünlüğünün uluslararası akademide kabul gördüğünü ortaya koymaktadır."
    },
    {
        soru: "<b>Türk-İslam medeniyetinde İmam Gazali'nin (1058-1111) Tehâfütü'l-Felâsife (Filozofların Tutarsızlığı) adlı eseri ile İbn Rüşd'ün (1126-1198) Tehâfütü't-Tehâfüt adlı yanıtı, dönemin entelektüel iklimini nasıl yansıtmaktadır?</b>",
        secenekler: [
            "A) Bu tartışma, İslam dünyasının felsefeyi tamamen reddettiğini ve yalnızca dini ilimlere yöneldiğini göstermektedir.",
            "B) Bu tartışma, İslam medeniyetinin içinde filozoflar ile kelamcılar arasındaki canlı entelektüel çatışmayı ve özgür fikir tartışması kültürünü yansıtmaktadır.",
            "C) Bu eserler, Türk-İslam medeniyetinde bilim ve felsefenin hiçbir zaman gelişmediğini kanıtlamaktadır.",
            "D) Bu tartışmanın Türk-İslam medeniyetiyle doğrudan bir ilgisi yoktur; salt Arap entelektüel dünyasına özgüdür.",
            "E) Gazali ve İbn Rüşd'ün tartışması yalnızca önemsiz teknik teolojik ayrıntılar üzerine olduğundan tarihsel önemi sınırlıdır."
        ],
        cevap: "B) Bu tartışma, İslam medeniyetinin içinde filozoflar ile kelamcılar arasındaki canlı entelektüel çatışmayı ve özgür fikir tartışması kültürünü yansıtmaktadır.",
        aciklama: "Gazali'nin Tehâfüt'ü (1095), aristotelci filozoflara yönelik kapsamlı bir eleştiri olup Yunan felsefesinin İslam inancıyla çelişen tezlerini hedef almıştır. İbn Rüşd'ün yanıtı ise bu eleştiriyi sistematik biçimde çürütmeye girişmiştir. Bu tartışma; İslam dünyasının monolitik bir düşünce yapısına sahip olmadığını, aksine keskin iç gerilimler ve entelektüel çoğulculuk barındırdığını somut biçimde ortaya koymaktadır. Üstelik Gazali yalnızca mistik değil; aynı zamanda analitik bir düşünür olarak özgün bir felsefi sentez üretmiştir. Bu tartışma, Batı ortaçağ skolastisizmini de derinden etkilemiştir."
    },
    {
        soru: "<b>Türk-İslam sanatında yazı (hat sanatı) neden diğer plastik sanat dalları arasında ayrıcalıklı bir yer tutmaktadır? Bu soruya verilen aşağıdaki yanıtlardan hangisi tarihsel ve estetik gerçeklikle en uyumludur?</b>",
        secenekler: [
            "A) Hat sanatının gelişimi, figüratif sanata getirilen İslami kısıtlamaların bir sonucu olarak açıklanabilir; ancak bu indirgemeci yorum yetersiz kalır.",
            "B) Hat yalnızca dini metinlerin yazılması için kullanılmış; estetik kaygılar taşımamaktadır.",
            "C) Hat sanatı, İslam dünyasında figüratif sanata getirilen kısıtlamalar nedeniyle gelişmiş ve bu ilişki dışında hiçbir açıklaması yoktur.",
            "D) Hat sanatı yalnızca Osmanlı döneminde gelişmiş; Selçuklu döneminde sanatsal bir değer taşımamıştır.",
            "E) Hat sanatının gelişiminde Türk kültürünün dile verdiği önemin herhangi bir rolü olmamıştır."
        ],
        cevap: "A) Hat sanatının gelişimi, figüratif sanata getirilen İslami kısıtlamaların bir sonucu olarak açıklanabilir; ancak bu indirgemeci yorum yetersiz kalır.",
        aciklama: "Hat sanatının İslam-Türk medeniyetindeki önemi, birkaç faktörün kesişiminden kaynaklanmaktadır. Kur'an metnine duyulan saygı, sözcüğün kutsal boyutu ve dini figüratif sanata yönelik hassasiyetler hat gelişimini hızlandıran nedenler arasındadır. Ancak hat sanatını yalnızca kısıtlamaların ürünü olarak açıklamak indirgemeci bir yaklaşımdır. Hat; Selçuklu döneminde mimari süslemede (yapı kitabeleri, taçkapı yazıları), el yazmalarında ve kervansaray duvarlarında estetik bir dile dönüşmüştür. Türk kültürünün söze verdiği öncem hattın gelişimine de katkı sunmuştur. A seçeneği bu karmaşıklığı kabul ederek indirgemeci yorumun yetersizliğini vurguladığından en doğru yanıttır."
    },
    {
        soru: "<b>Aşağıdaki ifadelerden hangisi Türk-İslam medeniyetinin bilimsel mirasını değerlendiren günümüz tarih yazımının genel eğilimini en doğru biçimde yansıtır?</b>",
        secenekler: [
            "A) Türk-İslam medeniyeti yalnızca Avrupa Rönesansı'na kaynaklık eden bir aktarım köprüsüdür; özgün bilimsel katkısı yoktur.",
            "B) Türk-İslam medeniyeti kendi içinde özgün ve yaratıcı bir bilim geleneği geliştirmiştir; bu gelenek yalnızca bir 'köprü' değil; bağımsız bir medeniyet atılımı olarak değerlendirilmelidir.",
            "C) Türk-İslam medeniyetinin bilimsel katkısı Batı akademisinde hâlâ tartışmalı olduğundan herhangi bir değerlendirme yapmak erkendir.",
            "D) Bu medeniyetin bilimsel mirası, yalnızca din ve siyasetle iç içe geçtiği için bağımsız bilimsel düşünce üretmediği kabul görmektedir.",
            "E) Türk-İslam medeniyeti matematiksel bilimlerde öne çıkmış; ancak doğa bilimleri ve tıp alanında herhangi bir özgün katkı sunamamıştır."
        ],
        cevap: "B) Türk-İslam medeniyeti kendi içinde özgün ve yaratıcı bir bilim geleneği geliştirmiştir; bu gelenek yalnızca bir 'köprü' değil; bağımsız bir medeniyet atılımı olarak değerlendirilmelidir.",
        aciklama: "Günümüz bilim tarihi araştırmaları, Türk-İslam medeniyetinin bilimsel katkısını 'Yunan bilimini Batı'ya aktaran köprü' şeklindeki indirgemeci yorumun çok ötesine geçen bir düzeyde değerlendirmektedir. Biruni'nin dünya çapına yaklaşımı, İbn Sina'nın tıp sistematiği, Harezmi'nin cebir alanındaki kurucu katkısı ve astronomideki özgün gözlemler; bu geleneğin bağımsız ve yaratıcı bir bilimsel üretim kapasitesine sahip olduğunu açıkça kanıtlamaktadır. Dimitri Gutas, George Saliba ve Aydin Sayılı gibi araştırmacılar, Türk-İslam bilim geleneğini bağımsız bir medeniyet atılımı olarak ele alan kapsamlı akademik çalışmalar ortaya koymuştur. Bu eğilim, günümüz küresel bilim tarihi yazımında giderek daha güçlü bir zemin kazanmaktadır."
    }
];
